 }}" @selected($value('grade_id')===$grade->id)>{{ $grade->name }}</option>@endforeach</select></div><div><label for="capacity">Capacity</label><input id="capacity" type="number" min="1" name="capacity" value="{{ $value('capacity') }}"></div><div><label><input type="hidden" name="is_homeroom" value="0"><input type="checkbox" name="is_homeroom" value="1" @checked((bool)$value('is_homeroom'))> Homeroom class</label></div>@endif @if($area==='subjects')<div><label for="department_id">Department</label><select id="department_id" name="department_id"><option value="">Not assigned</option>@foreach($departments as $department)<option value="{{ $department->id }}" @selected($value('department_id')===$department->id)>{{ $department->name }}</option>@endforeach</select></div>@endif @if(in_array($area,['grades','timetable-periods']))<div><label for="order">Order</label><input id="order" type="number" min="1" name="order" required value="{{ $value('order',1) }}"></div>@endif @if($area==='timetable-periods')<div><label for="day_of_week">Day</label><select id="day_of_week" name="day_of_week">@foreach(['monday','tuesday','wednesday','thursday','friday','saturday','sunday'] as $day)<option value="{{ $day }}" @selected($value('day_of_week')===$day)>{{ ucfirst($day) }}</option>@endforeach</select></div><div><label for="start_time">Start time</label><input id="start_time" type="time" name="start_time" required value="{{ substr((string)$value('start_time'),0,5) }}"></div><div><label for="end_time">End time</label><input id="end_time" type="time" name="end_time" required value="{{ substr((string)$value('end_time'),0,5) }}"></div><div><label><input type="hidden" name="is_break" value="0"><input type="checkbox" name="is_break" value="1" @checked((bool)$value('is_break'))> Break period</label></div>@endif @if(!in_array($area,['curricula','departments']))<div><label for="status">Status</label><select id="status" name="status">@foreach(['active','inactive','archived'] as $status)<option value